"use client";

import { useParams, useNavigate, useLocation } from "react-router-dom";
import { useState, useEffect } from "react";
import Navbar from "../navbar";
import Footer from "../footer";
import CartSidebarWrapper from "../shopcart/CartSidebarWrapper";

export default function DetailProductPage() {
    const { id } = useParams();
    const navigate = useNavigate();
    const location = useLocation();

    const products = location.state?.products || [];
    const [product, setProduct] = useState(null);
    const [isCartOpen, setIsCartOpen] = useState(false);
    const [cartItems, setCartItems] = useState([]);

    useEffect(() => {
        const found = products.find((p) => p.id === parseInt(id));
        if (found) setProduct(found);
        else navigate("/"); // ถ้าไม่เจอสินค้า กลับหน้า Home
    }, [id, products, navigate]);

    const addToCart = (item) => {
        const exist = cartItems.find((c) => c.id === item.id);
        if (exist) {
            setCartItems((prev) =>
                prev.map((c) =>
                    c.id === item.id ? { ...c, qty: c.qty + 1 } : c
                )
            );
        } else {
            setCartItems((prev) => [
                ...prev,
                { ...item, qty: 1, stock: 10 },
            ]);
        }
    };

    if (!product) return null;

    return (
        <div className="font-sans bg-white relative">
            <Navbar cartItems={cartItems} onCartOpen={() => setIsCartOpen(true)} />

            <main className="max-w-6xl mx-auto px-6 py-6">
                {/* Breadcrumb */}
                <div className="text-sm text-gray-500 mb-6">
                    <span
                        className="cursor-pointer hover:text-green-600"
                        onClick={() => navigate("/")}
                    >
                        Home
                    </span>{" "}
                    / {product.category} /{" "}
                    <span className="text-gray-800">{product.name}</span>
                </div>

                {/* Product Section */}
                <div className="flex flex-col lg:flex-row gap-10">
                    {/* Left images */}
                    <div className="flex flex-col gap-3">
                        <img
                            src={product.image}
                            alt={product.name}
                            className="w-96 h-96 object-contain border rounded"
                        />
                        <div className="flex gap-2">
                            <img
                                src={product.image}
                                alt="thumb1"
                                className="w-24 h-24 object-contain border rounded"
                            />
                            <img
                                src={product.image}
                                alt="thumb2"
                                className="w-24 h-24 object-contain border rounded"
                            />
                            <img
                                src={product.image}
                                alt="thumb3"
                                className="w-24 h-24 object-contain border rounded"
                            />
                        </div>
                    </div>

                    {/* Right details */}
                    <div className="flex-1">
                        <p className="text-green-600 text-sm font-medium mb-1">
                            {product.category}
                        </p>
                        <h1 className="text-2xl font-semibold mb-2">
                            {product.name}
                        </h1>
                        <p className="text-2xl text-gray-800 mb-4">
                            ${product.price.toFixed(2)}
                        </p>

                        {/* Qty + Add to cart */}
                        <div className="flex items-center gap-3 mb-6">
                            <div className="flex items-center border rounded">
                                <button className="px-3 py-1">-</button>
                                <span className="px-4">1</span>
                                <button className="px-3 py-1">+</button>
                            </div>
                            <button
                                onClick={() => addToCart(product)}
                                className="bg-green-600 text-white px-6 py-2 rounded hover:bg-green-700"
                            >
                                Add to cart
                            </button>
                            <button className="border px-3 py-2 rounded hover:bg-gray-100">
                                ♥
                            </button>
                        </div>

                        {/* Product info */}
                        <div className="space-y-1 text-sm">
                            <p>
                                <span className="font-medium">Product code:</span>{" "}
                                P{product.id.toString().padStart(5, "0")}
                            </p>
                            <p className="text-green-600">
                                <span className="font-medium">In stock:</span> 2500
                            </p>
                            <p>
                                <span className="font-medium">Type:</span>{" "}
                                {product.category}
                            </p>
                            <p>
                                <span className="font-medium">Shipping:</span>{" "}
                                01/01/2025
                            </p>
                        </div>

                        {/* Product Details */}
                        <div className="mt-8">
                            <h3 className="font-semibold text-lg mb-2">
                                Product Details
                            </h3>
                            <p className="text-sm text-gray-700 leading-relaxed">
                                Benefits: {product.desc}
                            </p>
                            <p className="text-sm text-gray-700">
                                Unit: 1 bottle (450–500 ml)
                            </p>
                            <p className="text-sm text-gray-700">
                                Seller: Be Nice / Official retailers
                            </p>
                            <p className="text-xs text-gray-500 mt-2">
                                Disclaimer: Images are for reference only. Please
                                check packaging for exact details.
                            </p>
                        </div>
                    </div>
                </div>

                {/* Related Items */}
                <div className="mt-12">
                    <h3 className="font-semibold text-lg mb-4">Related Items</h3>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                        {products
                            .filter(
                                (p) =>
                                    p.category === product.category &&
                                    p.id !== product.id
                            )
                            .map((p) => (
                                <div
                                    key={p.id}
                                    className="border rounded-lg p-3 hover:shadow"
                                >
                                    <img
                                        src={p.image}
                                        alt={p.name}
                                        className="w-full h-32 object-contain mb-2"
                                    />
                                    <p className="text-sm line-clamp-2">{p.name}</p>
                                    <p className="text-sm font-semibold">
                                        ${p.price.toFixed(2)}
                                    </p>
                                    <button
                                        onClick={() =>
                                            navigate(`/product/${p.id}`, {
                                                state: { products },
                                            })
                                        }
                                        className="bg-green-600 text-white text-xs px-3 py-1 rounded mt-2 hover:bg-green-700"
                                    >
                                        View
                                    </button>
                                </div>
                            ))}
                    </div>
                </div>
            </main>

            <Footer />

            {/* Cart Sidebar */}
            <CartSidebarWrapper
                isCartOpen={isCartOpen}
                onClose={() => setIsCartOpen(false)}
                cartItems={cartItems}
                increaseQty={() => {}}
                decreaseQty={() => {}}
                removeItem={() => {}}
            />
        </div>
    );
}
